import React, { useState, useEffect, createContext, useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Link, Navigate, useNavigate } from 'react-router-dom';
import './App.css';

// API Base URL
const API_BASE = 'http://localhost:3001/api';

// Auth Context
const AuthContext = createContext(null);
const useAuth = () => useContext(AuthContext);

// API Helper
const api = {
  get: async (url) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${url}`, {
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return res.json();
  },
  post: async (url, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${url}`, {
      method: 'POST',
      headers: { 
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(data)
    });
    return res.json();
  },
  put: async (url, data) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${url}`, {
      method: 'PUT',
      headers: { 
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(data)
    });
    return res.json();
  },
  delete: async (url) => {
    const token = localStorage.getItem('token');
    const res = await fetch(`${API_BASE}${url}`, {
      method: 'DELETE',
      headers: { 'Authorization': `Bearer ${token}` }
    });
    return res.json();
  }
};

// Login Page
function LoginPage() {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API_BASE}/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
      });
      const data = await res.json();
      if (data.success) {
        login(data.token, data.user);
        navigate('/');
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Connection error');
    }
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-header">
          <div className="login-logo">
            <svg viewBox="0 0 100 100">
              <circle cx="50" cy="50" r="45" fill="#1a365d" stroke="#2c5282" strokeWidth="2"/>
              <path d="M50 20 L50 80 M30 40 L50 20 L70 40" stroke="#fff" strokeWidth="4" fill="none" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="50" cy="55" r="15" stroke="#2c5282" strokeWidth="2" fill="none"/>
            </svg>
          </div>
          <h1>Sanaduk Saving and Credit Cooperative Ltd.</h1>
          <p>Member Management System</p>
        </div>
        <form onSubmit={handleSubmit} className="login-form">
          {error && <div className="error-message">{error}</div>}
          <input type="text" placeholder="Username" value={username} onChange={e => setUsername(e.target.value)} required />
          <input type="password" placeholder="Password" value={password} onChange={e => setPassword(e.target.value)} required />
          <button type="submit">Login</button>
        </form>
        <div className="login-footer">
          <p>Default: admin / admin123</p>
        </div>
      </div>
    </div>
  );
}

// Dashboard
function Dashboard() {
  const [stats, setStats] = useState({ members: 0, loans: 0, shares: 0, savings: 0 });

  useEffect(() => {
    const fetchStats = async () => {
      const [members, loans, shares, savings] = await Promise.all([
        api.get('/members/count'),
        api.get('/loans/count'),
        api.get('/shares/count'),
        api.get('/savings/count')
      ]);
      setStats({
        members: members.count || 0,
        loans: loans.count || 0,
        shares: shares.count || 0,
        savings: savings.count || 0
      });
    };
    fetchStats();
  }, []);

  return (
    <div className="dashboard">
      <div className="welcome-section">
        <h1>Welcome to Sanaduk Saving and Credit Cooperative Ltd.</h1>
        <p>Empowering communities through cooperative savings and financial services since 2075 B.S.</p>
      </div>
      <div className="stats-grid">
        <div className="stat-card">
          <h3>Total Members</h3>
          <div className="stat-number">{stats.members}</div>
        </div>
        <div className="stat-card">
          <h3>Active Loans</h3>
          <div className="stat-number">{stats.loans}</div>
        </div>
        <div className="stat-card">
          <h3>Share Members</h3>
          <div className="stat-number">{stats.shares}</div>
        </div>
        <div className="stat-card">
          <h3>Savings Accounts</h3>
          <div className="stat-number">{stats.savings}</div>
        </div>
      </div>
      <div className="dashboard-info">
        <div className="info-card">
          <h3>About Sanaduk Cooperative</h3>
          <p>
            Sanaduk Saving and Credit Cooperative Ltd. is a community-based financial institution 
            dedicated to empowering individuals and families through accessible savings and loan services. 
            Established with the vision of promoting financial inclusion and community development, 
            we provide secure ways for members to grow their savings while accessing affordable credit 
            for their personal and business needs. Our cooperative operates on the principles of mutual 
            benefit, transparency, and democratic governance, ensuring that every member has an equal 
            voice in the cooperative's direction.
          </p>
        </div>
      </div>
    </div>
  );
}

// Members Page
function MembersPage() {
  const [members, setMembers] = useState([]);
  const [filter, setFilter] = useState('');
  const [form, setForm] = useState({
    member_number: '', member_name: '', address: '', phone: '', email: '', 
    citizenship_number: '', citizenship_issued_place: '', citizenship_issued_date: '',
    date_of_birth: '', occupation: '', annual_income: '', membership_date: '',
    membership_type: 'Regular', status: 'Active', nominee_name: '', nominee_relation: ''
  });
  const [editingId, setEditingId] = useState(null);

  useEffect(() => { fetchMembers(); }, []);

  const fetchMembers = async () => {
    try {
      const response = await api.get('/members');
      const membersData = response.data || response || [];
      setMembers(Array.isArray(membersData) ? membersData : []);
    } catch (error) {
      console.error('Error fetching members:', error);
      setMembers([]);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (editingId) {
      await api.put(`/members/${editingId}`, form);
    } else {
      await api.post('/members', form);
    }
    fetchMembers();
    resetForm();
  };

  const handleEdit = (member) => {
    setForm(member);
    setEditingId(member.id);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Delete this member?')) {
      await api.delete(`/members/${id}`);
      fetchMembers();
    }
  };

  const resetForm = () => {
    setForm({
      member_number: '', member_name: '', address: '', phone: '', email: '', 
      citizenship_number: '', citizenship_issued_place: '', citizenship_issued_date: '',
      date_of_birth: '', occupation: '', annual_income: '', membership_date: '',
      membership_type: 'Regular', status: 'Active', nominee_name: '', nominee_relation: ''
    });
    setEditingId(null);
  };

  const filteredMembers = members.filter(m => 
    m.member_name.toLowerCase().includes(filter.toLowerCase()) ||
    m.member_number.toLowerCase().includes(filter.toLowerCase())
  );

  return (
    <div className="members-page">
      <div className="page-header">
        <h1>Members Management</h1>
        <p>Add, view, edit, and manage cooperative members</p>
      </div>
      <div className="form-section">
        <h2>{editingId ? 'Edit Member' : 'Add New Member'}</h2>
        <form onSubmit={handleSubmit}>
          <div className="form-row">
            <input type="text" placeholder="Member Number *" value={form.member_number} onChange={e => setForm({...form, member_number: e.target.value})} required />
            <input type="text" placeholder="Full Name *" value={form.member_name} onChange={e => setForm({...form, member_name: e.target.value})} required />
            <input type="date" placeholder="Date of Birth" value={form.date_of_birth} onChange={e => setForm({...form, date_of_birth: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="text" placeholder="Citizenship Number" value={form.citizenship_number} onChange={e => setForm({...form, citizenship_number: e.target.value})} />
            <input type="text" placeholder="Issued District" value={form.citizenship_issued_place} onChange={e => setForm({...form, citizenship_issued_place: e.target.value})} />
            <input type="date" placeholder="Issued Date" value={form.citizenship_issued_date} onChange={e => setForm({...form, citizenship_issued_date: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="text" placeholder="Address" value={form.address} onChange={e => setForm({...form, address: e.target.value})} />
            <input type="text" placeholder="Phone *" value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} required />
            <input type="email" placeholder="Email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
          </div>
          <div className="form-row">
            <input type="text" placeholder="Occupation" value={form.occupation} onChange={e => setForm({...form, occupation: e.target.value})} />
            <input type="number" placeholder="Annual Income" value={form.annual_income} onChange={e => setForm({...form, annual_income: e.target.value})} />
            <input type="date" placeholder="Membership Date" value={form.membership_date} onChange={e => setForm({...form, membership_date: e.target.value})} />
          </div>
          <div className="form-row">
            <select value={form.membership_type} onChange={e => setForm({...form, membership_type: e.target.value})}>
              <option value="Regular">Regular</option>
              <option value="Foundation">Foundation</option>
              <option value="Honorary">Honorary</option>
            </select>
            <select value={form.status} onChange={e => setForm({...form, status: e.target.value})}>
              <option value="Active">Active</option>
              <option value="Inactive">Inactive</option>
              <option value="Suspended">Suspended</option>
            </select>
            <input type="text" placeholder="Nominee Name" value={form.nominee_name} onChange={e => setForm({...form, nominee_name: e.target.value})} />
            <input type="text" placeholder="Nominee Relation" value={form.nominee_relation} onChange={e => setForm({...form, nominee_relation: e.target.value})} />
          </div>
          <div style={{ display: 'flex', gap: '12px', marginTop: '10px' }}>
            <button type="submit" className="btn-primary">{editingId ? 'Update' : 'Add Member'}</button>
            {editingId && <button type="button" onClick={resetForm}>Cancel</button>}
          </div>
        </form>
      </div>
      <div className="filter-bar">
        <input type="text" placeholder="Search members..." value={filter} onChange={e => setFilter(e.target.value)} />
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Member #</th>
              <th>Name</th>
              <th>Phone</th>
              <th>Type</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredMembers.map(m => (
              <tr key={m.id}>
                <td>{m.member_number}</td>
                <td>{m.member_name}</td>
                <td>{m.phone}</td>
                <td>{m.membership_type}</td>
                <td><span className={`status-badge ${m.status.toLowerCase()}`}>{m.status}</span></td>
                <td>
                  <button className="btn-sm" onClick={() => handleEdit(m)}>Edit</button>
                  <button className="btn-sm btn-danger" onClick={() => handleDelete(m.id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// Loan Page
function LoanPage() {
  const [loans, setLoans] = useState([]);
  const [members, setMembers] = useState([]);
  const [filter, setFilter] = useState('');
  const [form, setForm] = useState({
    loan_number: '', member_id: '', loan_type: 'Personal', principal_amount: '', 
